 9→
10→export default function Slider(props: Props) {
11→  let ref!: HTMLDivElement;
12→  const [value, setValue] = createSignal(props.initialValue ?? 0.5);
13→  let dragging = false;
14→
15→  onMount(() => {
16→    props.renderer.sliders.push({
17→      ref: () => ref,
18→      value,
19→    });
20→  });
21→
22→  const updateFromEvent = (e: MouseEvent | TouchEvent) => {
23→    if (!ref) return;
24→    const rect = ref.getBoundingClientRect();
25→    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
26→    const pct = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
27→    setValue(pct);
28→  };
29→
30→  const onMove = (e: MouseEvent | TouchEvent) => {
31→    if (!dragging) return;
32→    e.preventDefault();
33→    updateFromEvent(e);
34→  };
35→  const onUp = () => {
36→    dragging = false;
37→    document.removeEventListener('mousemove', onMove);
38→    document.removeEventListener('mouseup', onUp);
39→    document.removeEventListener('touchmove', onMove);
40→    document.removeEventListener('touchend', onUp);
41→  };
42→
43→  const onDown = (e: MouseEvent | TouchEvent) => {
44→    e.preventDefault();
45→    dragging = true;
46→    updateFromEvent(e);
47→    document.addEventListener('mousemove', onMove);
48→    document.addEventListener('mouseup', onUp);
49→    document.addEventListener('touchmove', onMove, { passive: false });
50→    document.addEventListener('touchend', onUp);
51→  };
52→
53→  onCleanup(onUp);
54→
55→  return (
56→    <div class="bar-row">
57→      <span class="bar-label">{props.label}</span>
58→      <div
59→        ref={ref}
60→        class="wc3-slider"
61→        onMouseDown={onDown}
62→        onTouchStart={onDown}
63→      >
64→        <img class="slider-bg" src="" alt="" />
65→        <img class="slider-border" src="" alt="" />
66→        <img class="slider-knob" src="" alt="" style={{ left: (value() * 100) + '%' }} />
67→      </div>
68→    </div>
69→  );
70→}
