 70→function findTransparentSeed(alpha: Uint8ClampedArray, width: number, height: number, startX: number, startY: number): number {
 71→  const inBounds = (x: number, y: number) => x >= 0 && y >= 0 && x < width && y < height;
 72→  const alphaAt = (x: number, y: number) => alpha[(y * width + x) * 4 + 3];
 73→  if (inBounds(startX, startY) && alphaAt(startX, startY) === 0) {
 74→    return startY * width + startX;
 75→  }
 76→  const maxRadius = Math.max(width, height);
 77→  for (let r = 1; r < maxRadius; r++) {
 78→    for (let dy = -r; dy <= r; dy++) {
 79→      const y = startY + dy;
 80→      const x1 = startX - r;
 81→      const x2 = startX + r;
 82→      if (inBounds(x1, y) && alphaAt(x1, y) === 0) return y * width + x1;
 83→      if (inBounds(x2, y) && alphaAt(x2, y) === 0) return y * width + x2;
 84→    }
 85→    for (let dx = -r + 1; dx <= r - 1; dx++) {
 86→      const x = startX + dx;
 87→      const y1 = startY - r;
 88→      const y2 = startY + r;
 89→      if (inBounds(x, y1) && alphaAt(x, y1) === 0) return y1 * width + x;
 90→      if (inBounds(x, y2) && alphaAt(x, y2) === 0) return y2 * width + x;
 91→    }
 92→  }
 93→  return -1;
 94→}
