import { useEffect, useRef } from 'react';
import type { Renderer } from '../renderer/Renderer';

interface Props {
  label: string;
  type: 'health' | 'mana' | 'xp' | 'build';
  fillPercent: number;
  maxValue?: number;
  height?: number;
  hasBorder?: boolean;
  renderer: Renderer;
}

export default function StatBar(props: Props) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    props.renderer.statBars.push({
      ref: () => ref.current!,
      fillPercent: () => props.fillPercent,
      type: props.type,
      hasBorder: !!props.hasBorder,
    });
