192→  const pxH = Math.max(1, Math.round(cssH * dpr));
193→  if (canvas.width !== pxW || canvas.height !== pxH) {
194→    canvas.width = pxW;
195→    canvas.height = pxH;
196→  }
197→
198→  const ctx = canvas.getContext('2d');
199→  if (!ctx) return;
