 54→      const materials: Array<{ Layers?: Array<{ TextureID?: number }> }> = model.Materials || [];
 55→      const borderMaterialIndex = materials.findIndex((material) =>
 56→        (material?.Layers || []).some((layer) => layer?.TextureID === borderTexIndex),
