 96→function deriveBuildBarCapRatio(
 97→  borderImg: HTMLImageElement,
 98→  uvDomain: { minU: number; maxU: number },
 99→): number {
100→  const width = borderImg.width;
101→  const height = borderImg.height;
102→  if (width <= 2 || height <= 0) return fallbackCapRatio;
103→
104→  const scratch = document.createElement('canvas');
105→  scratch.width = width;
106→  scratch.height = height;
107→  const scratchCtx = scratch.getContext('2d', { willReadFrequently: true });
108→  if (!scratchCtx) return fallbackCapRatio;
109→
110→  scratchCtx.clearRect(0, 0, width, height);
111→  scratchCtx.drawImage(borderImg, 0, 0);
112→  const data = scratchCtx.getImageData(0, 0, width, height).data;
113→  const row = Math.floor(height / 2);
114→
115→  const alphaAt = (x: number) => data[(row * width + x) * 4 + 3];
116→  let firstOpaque = 0;
117→  while (firstOpaque < width && alphaAt(firstOpaque) === 0) firstOpaque += 1;
118→
119→  let firstGap = firstOpaque;
120→  while (firstGap < width && alphaAt(firstGap) !== 0) firstGap += 1;
121→  if (firstGap <= firstOpaque || firstGap >= width) return fallbackCapRatio;
122→
123→  const uSpan = Math.max(1e-6, uvDomain.maxU - uvDomain.minU);
124→  const uAtGap = firstGap / width;
125→  const ratio = (uAtGap - uvDomain.minU) / uSpan;
126→  return Math.max(1 / width, Math.min(0.45, ratio));
127→}
