        <h2>Border Textures</h2>
        <p class="section-desc">
          All {ALL_BORDER_PATHS.length} border BLP textures across {BORDER_CATEGORIES.length} categories.
          These 9-slice atlases, bar borders, and panel borders define the chrome around every UI element.
        </p>
        <Show when={!loading()} fallback={<div class="borders-loading">Decoding border textures…</div>}>
          <For each={BORDER_CATEGORIES}>
            {(cat) => (
              <div class="borders-category">
                <h4 class="borders-category-title">{cat.title}</h4>
                <p class="borders-category-desc">{cat.desc}</p>
                <div class="borders-grid">
                  <For each={cat.entries}>
                    {(entry) => {
                      const image = () => rendered()[entry.path];
                      return (
                        <Show when={image()}>
                          <div class="border-item">
                            <img class="border-thumbnail" src={image()!.previewUrl} alt={entry.label} />
                            <div class="border-label">{entry.label}</div>
                          </div>
                        </Show>
                      );
                    }}
                  </For>
                </div>
              </div>
            )}
          </For>
        </Show>
      </div>
    </div>
  );
}

