              className="esc-option-label"
              style={{
                transform: props.getStartedPressed ? 'translate(2px, 2px)' : 'none',
              }}
            >
              {'Get\u00A0'}<span className="button-hotkey">S</span>tarted
            </span>
          </button>

          <label className="wc3-editbox wc3-editbox--esc hero-install-editbox" onClick={handleCopy}>
            <canvas ref={props.installCanvasRef} className="wc3-editbox-canvas" />
            <input
              type="text"
              value="npm i wc3ui"
              readOnly
              aria-label="Copy install command"
              onFocus={(event) => event.currentTarget.select()}
