import { useEffect, useRef } from 'react';
import type { Race } from '../lib/types';
import { RACE_PREFIXES } from '../state/race';

interface Props {
  race: Race;
  leftOnly?: boolean;
}

type TileIndex = 1 | 2 | 3 | 4;

const TILE_INDICES: readonly TileIndex[] = [1, 2, 3, 4];
const TOP_SLICE_V0 = 0;
const TOP_SLICE_V1 = 0.125;
const TILE2_LEFT_U0 = 0;
const TILE2_LEFT_U1 = 0.33984375;
const TILE2_RIGHT_U0 = 0.79296875;
const TILE2_RIGHT_U1 = 1;

const LEFT_TILE1_WIDTH_VW = 32;
const LEFT_TILE2_WIDTH_VW = 10.875;
const RIGHT_TILE2_WIDTH_VW = 6.875;
const RIGHT_TILE3_WIDTH_VW = 32;
const RIGHT_TILE4_WIDTH_VW = 4;
const SEAM_PX = 1;

function topTilePath(race: Race, index: TileIndex): string {
  const tile = RACE_PREFIXES[race].tile;
  return `/console/${race}/${tile}UITile0${index}.png`;
}

function compileShader(gl: WebGLRenderingContext, type: number, src: string): WebGLShader | null {
  const shader = gl.createShader(type);
  if (!shader) return null;
  gl.shaderSource(shader, src);
  gl.compileShader(shader);
  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    console.error('Top HUD shader compile failed:', gl.getShaderInfoLog(shader));
    gl.deleteShader(shader);
    return null;
  }
  return shader;
}

function createProgram(gl: WebGLRenderingContext): WebGLProgram | null {
  const vertexSource = `
    attribute vec2 a_position;
    attribute vec2 a_uv;
    varying vec2 v_uv;
    void main() {
      gl_Position = vec4(a_position, 0.0, 1.0);
      v_uv = a_uv;
    }
  `;
  const fragmentSource = `
    precision mediump float;
    varying vec2 v_uv;
    uniform sampler2D u_texture;
    void main() {
      vec4 color = texture2D(u_texture, v_uv);
      if (color.a < 0.5) {
        discard;
      }
      gl_FragColor = color;
    }
  `;

  const vertexShader = compileShader(gl, gl.VERTEX_SHADER, vertexSource);
  const fragmentShader = compileShader(gl, gl.FRAGMENT_SHADER, fragmentSource);
  if (!vertexShader || !fragmentShader) return null;

  const program = gl.createProgram();
  if (!program) return null;

  gl.attachShader(program, vertexShader);
  gl.attachShader(program, fragmentShader);
  gl.linkProgram(program);

  gl.deleteShader(vertexShader);
  gl.deleteShader(fragmentShader);

  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    console.error('Top HUD program link failed:', gl.getProgramInfoLog(program));
    gl.deleteProgram(program);
    return null;
  }

  return program;
}

interface GLState {
  gl: WebGLRenderingContext | null;
  program: WebGLProgram | null;
  quadBuffer: WebGLBuffer | null;
  positionLoc: number;
  uvLoc: number;
  textureLoc: WebGLUniformLocation | null;
  destroyed: boolean;
  drawQueued: boolean;
  drawRaf: number;
  resizeObserver: ResizeObserver | null;
  textureCache: Map<string, WebGLTexture>;
  textureLoadCache: Map<string, Promise<WebGLTexture | null>>;
  activeTextures: Record<TileIndex, WebGLTexture> | null;
}

export default function TopHudWebGL(props: Props) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const propsRef = useRef(props);
  propsRef.current = props;

  const stateRef = useRef<GLState>({
    gl: null,
    program: null,
    quadBuffer: null,
    positionLoc: -1,
    uvLoc: -1,
    textureLoc: null,
    destroyed: false,
    drawQueued: false,
    drawRaf: 0,
    resizeObserver: null,
    textureCache: new Map(),
    textureLoadCache: new Map(),
    activeTextures: null,
  });

  useEffect(() => {
    const s = stateRef.current;
    const canvas = canvasRef.current!;

    const syncCanvasSize = () => {
      if (!s.gl) return;
      const dpr = window.devicePixelRatio || 1;
      const cssWidth = Math.max(1, canvas.clientWidth || 1);
      const cssHeight = Math.max(1, canvas.clientHeight || 1);
      const width = Math.round(cssWidth * dpr);
      const height = Math.round(cssHeight * dpr);
      if (canvas.width !== width || canvas.height !== height) {
        canvas.width = width;
        canvas.height = height;
      }
      s.gl.viewport(0, 0, width, height);
    };

    const drawQuad = (
      texture: WebGLTexture,
      x: number, y: number, w: number, h: number,
      u0: number, v0: number, u1: number, v1: number
    ) => {
      if (!s.gl || !s.quadBuffer) return;
      const canvasW = canvas.width;
      const canvasH = canvas.height;
      if (canvasW <= 0 || canvasH <= 0 || w <= 0 || h <= 0) return;
      const x0 = (x / canvasW) * 2 - 1;
      const y0 = 1 - (y / canvasH) * 2;
      const x1 = ((x + w) / canvasW) * 2 - 1;
      const y1 = 1 - ((y + h) / canvasH) * 2;
      const vertices = new Float32Array([
        x0, y0, u0, v0, x1, y0, u1, v0, x0, y1, u0, v1,
        x1, y0, u1, v0, x1, y1, u1, v1, x0, y1, u0, v1,
      ]);
      s.gl.bindTexture(s.gl.TEXTURE_2D, texture);
      s.gl.bindBuffer(s.gl.ARRAY_BUFFER, s.quadBuffer);
      s.gl.bufferData(s.gl.ARRAY_BUFFER, vertices, s.gl.STREAM_DRAW);
      s.gl.drawArrays(s.gl.TRIANGLES, 0, 6);
    };

    const draw = () => {
      if (!s.gl || !s.program || !s.quadBuffer || !s.activeTextures) return;
      syncCanvasSize();
      const canvasW = canvas.width;
      const canvasH = canvas.height;
      if (canvasW <= 0 || canvasH <= 0) return;
      s.gl.clear(s.gl.COLOR_BUFFER_BIT);
      s.gl.useProgram(s.program);
      s.gl.bindBuffer(s.gl.ARRAY_BUFFER, s.quadBuffer);
      s.gl.enableVertexAttribArray(s.positionLoc);
      s.gl.vertexAttribPointer(s.positionLoc, 2, s.gl.FLOAT, false, 16, 0);
      s.gl.enableVertexAttribArray(s.uvLoc);
      s.gl.vertexAttribPointer(s.uvLoc, 2, s.gl.FLOAT, false, 16, 8);
      s.gl.activeTexture(s.gl.TEXTURE0);
      s.gl.uniform1i(s.textureLoc, 0);

      const dpr = window.devicePixelRatio || 1;
      const seamPx = SEAM_PX * dpr;
      const vw = canvasW / 100;
      const topHudH = canvasH;
      const p = propsRef.current;

      if (p.leftOnly) {
        const leftSpanVw = LEFT_TILE1_WIDTH_VW + LEFT_TILE2_WIDTH_VW;
        const leftTile1W = (LEFT_TILE1_WIDTH_VW / leftSpanVw) * canvasW + seamPx;
        const leftTile2X = leftTile1W - seamPx;
        const leftTile2W = canvasW - leftTile2X;
        drawQuad(s.activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
        drawQuad(s.activeTextures[2], leftTile2X, 0, leftTile2W, topHudH, TILE2_LEFT_U0, TOP_SLICE_V0, TILE2_LEFT_U1, TOP_SLICE_V1);
        return;
      }

      const leftTile1W = LEFT_TILE1_WIDTH_VW * vw + seamPx;
      const leftTile2W = LEFT_TILE2_WIDTH_VW * vw + seamPx;
      const leftTile2X = leftTile1W - seamPx;
      drawQuad(s.activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
      drawQuad(s.activeTextures[2], leftTile2X, 0, leftTile2W, topHudH, TILE2_LEFT_U0, TOP_SLICE_V0, TILE2_LEFT_U1, TOP_SLICE_V1);

      const rightTile2W = RIGHT_TILE2_WIDTH_VW * vw + seamPx;
      const rightTile3W = RIGHT_TILE3_WIDTH_VW * vw + seamPx;
      const rightTile4W = RIGHT_TILE4_WIDTH_VW * vw + seamPx;
      const rightTile4X = canvasW - rightTile4W;
      const rightTile3X = rightTile4X - (rightTile3W - seamPx);
      const rightTile2X = rightTile3X - (rightTile2W - seamPx);
      drawQuad(s.activeTextures[2], rightTile2X, 0, rightTile2W, topHudH, TILE2_RIGHT_U0, TOP_SLICE_V0, TILE2_RIGHT_U1, TOP_SLICE_V1);
      drawQuad(s.activeTextures[3], rightTile3X, 0, rightTile3W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
      drawQuad(s.activeTextures[4], rightTile4X, 0, rightTile4W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
    };

    const requestDraw = () => {
      if (s.drawQueued || s.destroyed) return;
      s.drawQueued = true;
      s.drawRaf = window.requestAnimationFrame(() => {
        s.drawQueued = false;
        draw();
      });
    };

    const loadTexture = (path: string): Promise<WebGLTexture | null> => {
      if (!s.gl) return Promise.resolve(null);
      const cached = s.textureCache.get(path);
      if (cached) return Promise.resolve(cached);
      const inflight = s.textureLoadCache.get(path);
      if (inflight) return inflight;

      const promise = new Promise<WebGLTexture | null>((resolve) => {
        const image = new Image();
        image.onload = () => {
          if (!s.gl || s.destroyed) { s.textureLoadCache.delete(path); resolve(null); return; }
          const texture = s.gl.createTexture();
          if (!texture) { s.textureLoadCache.delete(path); resolve(null); return; }
          s.gl.bindTexture(s.gl.TEXTURE_2D, texture);
          s.gl.texImage2D(s.gl.TEXTURE_2D, 0, s.gl.RGBA, s.gl.RGBA, s.gl.UNSIGNED_BYTE, image);
          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_MIN_FILTER, s.gl.LINEAR);
          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_MAG_FILTER, s.gl.LINEAR);
          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_WRAP_S, s.gl.CLAMP_TO_EDGE);
          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_WRAP_T, s.gl.CLAMP_TO_EDGE);
          s.textureCache.set(path, texture);
          s.textureLoadCache.delete(path);
          resolve(texture);
        };
        image.onerror = () => {
          console.error(`Failed to load top HUD texture: ${path}`);
          s.textureLoadCache.delete(path);
          resolve(null);
        };
        image.src = path;
      });
      s.textureLoadCache.set(path, promise);
      return promise;
    };

    const loadRaceTextures = async (race: Race) => {
      if (!s.gl || s.destroyed) return;
      const paths = TILE_INDICES.map((index) => topTilePath(race, index));
      const loaded = await Promise.all(paths.map((path) => loadTexture(path)));
      if (s.destroyed || loaded.some((tex) => tex === null)) return;
      s.activeTextures = { 1: loaded[0]!, 2: loaded[1]!, 3: loaded[2]!, 4: loaded[3]! };
      requestDraw();
    };

    // Store for use in race/leftOnly effects
    (stateRef.current as any).loadRaceTextures = loadRaceTextures;
    (stateRef.current as any).requestDraw = requestDraw;

    s.gl = canvas.getContext('webgl', {
      alpha: true, premultipliedAlpha: false, antialias: false, depth: false, stencil: false,
    });
    if (!s.gl) { console.error('WebGL is unavailable for top HUD rendering.'); return; }

    s.program = createProgram(s.gl);
    if (!s.program) return;

    s.positionLoc = s.gl.getAttribLocation(s.program, 'a_position');
    s.uvLoc = s.gl.getAttribLocation(s.program, 'a_uv');
    s.textureLoc = s.gl.getUniformLocation(s.program, 'u_texture');
    s.quadBuffer = s.gl.createBuffer();

    if (s.positionLoc < 0 || s.uvLoc < 0 || !s.textureLoc || !s.quadBuffer) {
      console.error('Failed to initialize top HUD WebGL buffers.');
      return;
    }

    s.gl.disable(s.gl.DEPTH_TEST);
    s.gl.disable(s.gl.CULL_FACE);
    s.gl.enable(s.gl.BLEND);
    s.gl.blendFunc(s.gl.SRC_ALPHA, s.gl.ONE_MINUS_SRC_ALPHA);
    s.gl.clearColor(0, 0, 0, 0);

    void loadRaceTextures(propsRef.current.race);
    requestDraw();

    const onResize = () => requestDraw();
    window.addEventListener('resize', onResize);

    if (typeof ResizeObserver !== 'undefined') {
      s.resizeObserver = new ResizeObserver(() => requestDraw());
      s.resizeObserver.observe(canvas);
    }

    return () => {
      s.destroyed = true;
      window.removeEventListener('resize', onResize);
      if (s.resizeObserver) { s.resizeObserver.disconnect(); s.resizeObserver = null; }
      if (s.drawRaf) window.cancelAnimationFrame(s.drawRaf);
      if (s.gl) {
        for (const texture of s.textureCache.values()) s.gl.deleteTexture(texture);
        if (s.quadBuffer) s.gl.deleteBuffer(s.quadBuffer);
        if (s.program) s.gl.deleteProgram(s.program);
      }
    };
  }, []);

  // React to race changes
  useEffect(() => {
    const s = stateRef.current;
    if (!s.gl || s.destroyed) return;
    const loadRaceTextures = (s as any).loadRaceTextures as ((race: Race) => Promise<void>) | undefined;
    if (loadRaceTextures) void loadRaceTextures(props.race);
  }, [props.race]);

  // React to leftOnly changes
  useEffect(() => {
    const s = stateRef.current;
    const requestDraw = (s as any).requestDraw as (() => void) | undefined;
    if (requestDraw) requestDraw();
  }, [props.leftOnly]);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      style={{
        position: 'absolute',
        inset: '0',
        width: '100%',
        height: '100%',
        display: 'block',
        pointerEvents: 'none',
      }}
    />
  );
}

import { useEffect, useRef } from 'react';
import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
import { mat3, mat4, quat, vec3 } from 'gl-matrix';
import type { Race } from '../lib/types';

type ModelType = ReturnType<typeof parseMDX>;

interface HeroPortraitConfig {
  modelPath: string;
  textures: Record<string, string>;
}

const HERO_PORTRAIT_CONFIG: Record<Race, HeroPortraitConfig> = {
  Human: {
    modelPath: '/models/hero-portrait/Human/HeroArchMage_portrait.mdx',
    textures: { 'heroarchmage.blp': '/models/hero-portrait/textures/Human/HeroArchmage.blp' },
  },
  Orc: {
    modelPath: '/models/hero-portrait/Orc/HeroBladeMaster_portrait.mdx',
    textures: { 'heroblademaster.blp': '/models/hero-portrait/textures/Orc/HeroBladeMaster.blp' },
  },
  NightElf: {
    modelPath: '/models/hero-portrait/NightElf/HeroDemonHunter_Portrait.mdx',
    textures: {
      'herodemonhunter.blp': '/models/hero-portrait/textures/NightElf/HeroDemonHunter.blp',
      'black32.blp': '/models/hero-portrait/textures/NightElf/Black32.blp',
    },
  },
  Undead: {
    modelPath: '/models/hero-portrait/Undead/HeroDeathKnight_portrait.mdx',
    textures: { 'herodeathknight.blp': '/models/hero-portrait/textures/Undead/HeroDeathknight.blp' },
  },
};

const modelCache = new Map<string, ModelType>();
const blpCache = new Map<string, ImageData[]>();

function normalizeTextureName(textureImage: string): string {
  const normalized = textureImage.replaceAll('\\', '/');
  const lastSlash = normalized.lastIndexOf('/');
  return (lastSlash >= 0 ? normalized.slice(lastSlash + 1) : normalized).toLowerCase();
}

function getTexturePath(textureImage: string, race: Race): string | null {
  const key = normalizeTextureName(textureImage);
  const raceTexture = HERO_PORTRAIT_CONFIG[race].textures[key];
  if (raceTexture) return raceTexture;
  if (key.startsWith('teamcolor')) return '/models/hero-portrait/textures/shared/TeamColor00.blp';
  if (key.startsWith('teamglow')) return '/models/hero-portrait/textures/shared/TeamGlow00.blp';
  return null;
}

async function loadModel(race: Race): Promise<ModelType> {
  const path = HERO_PORTRAIT_CONFIG[race].modelPath;
  const cached = modelCache.get(path);
  if (cached) return cached;
  const res = await fetch(path);
  if (!res.ok) throw new Error(`Failed to load hero portrait model: ${path}`);
  const ab = await res.arrayBuffer();
  const model = parseMDX(ab);
  modelCache.set(path, model);
  return model;
}

async function loadBLPMips(path: string): Promise<ImageData[]> {
  const cached = blpCache.get(path);
  if (cached) return cached;
  const res = await fetch(path);
  if (!res.ok) throw new Error(`Failed to load hero portrait texture: ${path}`);
  const ab = await res.arrayBuffer();
  const blp = decodeBLP(ab);
  const mips: ImageData[] = [];
  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
  for (let i = 0; i < maxLevels; i++) {
    const w = blp.width >> i;
    const h = blp.height >> i;
    if (w <= 0 || h <= 0) break;
    try {
      const img = getBLPImageData(blp, i);
      if (!img || !img.width || !img.height) break;
      mips.push(new ImageData(img.data, img.width, img.height));
      if (img.width === 1 && img.height === 1) break;
    } catch { break; }
  }
  if (mips.length === 0) throw new Error(`No mip levels decoded for hero portrait texture: ${path}`);
  blpCache.set(path, mips);
  return mips;
}

function findPortraitSequenceIndex(model: ModelType): number {
  const sequences = model.Sequences || [];
  if (sequences.length === 0) return 0;
  const byName = (predicate: (name: string) => boolean) =>
    sequences.findIndex((seq) => predicate((seq.Name || '').toLowerCase()));
  let idx = byName((name) => name.includes('portrait') && !name.includes('talk'));
  if (idx >= 0) return idx;
  idx = byName((name) => name.includes('stand'));
  if (idx >= 0) return idx;
  idx = byName((name) => name.includes('portrait'));
  if (idx >= 0) return idx;
  return 0;
}

interface HeroPortraitModelProps {
  race: Race;
}

export default function HeroPortraitModel(props: HeroPortraitModelProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef({
    gl: null as WebGLRenderingContext | WebGL2RenderingContext | null,
    modelRenderer: null as ModelRenderer | null,
    resizeObserver: null as ResizeObserver | null,
    rafId: 0,
    disposed: false,
    initVersion: 0,
    mvMatrix: mat4.create(),
    pMatrix: mat4.create(),
    worldCameraMatrix: mat4.create(),
    cameraPos: vec3.create(),
    cameraTarget: vec3.create(),
    cameraQuat: quat.create(),
    cameraFov: 0.691111,
    cameraNear: 8,
    cameraFar: 1800,
  });

  useEffect(() => {
    const s = stateRef.current;
    const canvas = canvasRef.current!;

    const destroyRenderer = () => {
      if (!s.modelRenderer) return;
      try { s.modelRenderer.destroy(); } catch (err) { console.warn('hero portrait renderer destroy failed', err); }
      finally { s.modelRenderer = null; }
    };

    const updateProjection = () => {
      const aspect = Math.max(1e-6, canvas.clientWidth / Math.max(1, canvas.clientHeight));
      mat4.perspective(s.pMatrix, s.cameraFov, aspect, s.cameraNear, s.cameraFar);
    };

    const resizeCanvas = () => {
      if (!s.gl) return;
      const dpr = window.devicePixelRatio || 1;
      const w = Math.max(1, Math.round(canvas.clientWidth * dpr));
      const h = Math.max(1, Math.round(canvas.clientHeight * dpr));
      if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; }
      s.gl.viewport(0, 0, w, h);
      updateProjection();
    };

    const configureCamera = (model: ModelType) => {
      const cam = model.Cameras?.[0];
      if (cam) {
        vec3.set(s.cameraPos, cam.Position[0], cam.Position[1], cam.Position[2]);
        vec3.set(s.cameraTarget, cam.TargetPosition[0], cam.TargetPosition[1], cam.TargetPosition[2]);
        s.cameraFov = Math.max(0.35, cam.FieldOfView || 0.691111);
        s.cameraNear = Math.max(4, cam.NearClip || 8);
        s.cameraFar = Math.max(s.cameraNear + 100, cam.FarClip || 1800);
        mat4.lookAt(s.mvMatrix, s.cameraPos, s.cameraTarget, vec3.fromValues(0, 0, 1));
      } else {
        const min = model.Info?.MinimumExtent;
        const max = model.Info?.MaximumExtent;
        if (min && max) {
          const cx = (min[0] + max[0]) * 0.5, cy = (min[1] + max[1]) * 0.5, cz = (min[2] + max[2]) * 0.5;
          const radius = Math.max(140, model.Info?.BoundsRadius || 180);
          vec3.set(s.cameraPos, cx + radius * 0.2, cy - radius * 1.8, cz + radius * 0.2);
          vec3.set(s.cameraTarget, cx, cy, cz);
        } else {
          vec3.set(s.cameraPos, 0, -450, 120);
          vec3.set(s.cameraTarget, 0, 0, 110);
        }
        s.cameraFov = 0.691111; s.cameraNear = 8; s.cameraFar = 1800;
        mat4.lookAt(s.mvMatrix, s.cameraPos, s.cameraTarget, vec3.fromValues(0, 0, 1));
      }
      if (mat4.invert(s.worldCameraMatrix, s.mvMatrix)) {
        const rot = mat3.create();
        mat3.fromMat4(rot, s.worldCameraMatrix);
        quat.fromMat3(s.cameraQuat, rot);
        quat.normalize(s.cameraQuat, s.cameraQuat);
      } else { quat.identity(s.cameraQuat); }
    };

    const startRenderLoop = () => {
      let lastTs = performance.now();
      const tick = (now: number) => {
        if (s.disposed) return;
        s.rafId = requestAnimationFrame(tick);
        if (!s.gl || !s.modelRenderer) return;
        resizeCanvas();
        const delta = Math.min(100, now - lastTs);
        lastTs = now;
        s.modelRenderer.update(delta);
        s.gl.clearColor(0, 0, 0, 0);
        s.gl.clear(s.gl.COLOR_BUFFER_BIT | s.gl.DEPTH_BUFFER_BIT);
        s.modelRenderer.render(s.mvMatrix, s.pMatrix, { env: false, wireframe: false });
      };
      s.rafId = requestAnimationFrame(tick);
    };

    const initForRace = async (race: Race) => {
      const version = ++s.initVersion;
      const model = await loadModel(race);
      if (s.disposed || version !== s.initVersion || !s.gl) return;
      destroyRenderer();
      s.modelRenderer = new ModelRenderer(model);
      s.modelRenderer.initGL(s.gl);
      configureCamera(model);
      s.modelRenderer.setCamera(s.cameraPos, s.cameraQuat);
      s.modelRenderer.setLightPosition(s.cameraPos);
      s.modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
      s.modelRenderer.setSequence(findPortraitSequenceIndex(model));
      const texturePromises = (model.Textures || []).map(async (tex) => {
        const texturePath = getTexturePath(tex.Image, race);
        if (!texturePath) return;
        const mips = await loadBLPMips(texturePath);
        if (!s.disposed && version === s.initVersion) s.modelRenderer!.setTextureImageData(tex.Image, mips);
      });
      await Promise.all(texturePromises);
    };

    // Store initForRace for race-change effect
    (s as any).initForRace = initForRace;

    s.gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false }) as WebGL2RenderingContext | null;
    if (!s.gl) s.gl = canvas.getContext('webgl', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false });
    if (!s.gl) return;

    resizeCanvas();
    s.resizeObserver = new ResizeObserver(() => resizeCanvas());
    s.resizeObserver.observe(canvas);
    startRenderLoop();
    void initForRace(props.race).catch((err) => console.error(err));

    return () => {
      s.disposed = true;
      s.initVersion++;
      cancelAnimationFrame(s.rafId);
      s.resizeObserver?.disconnect();
      destroyRenderer();
    };
  }, []);

  useEffect(() => {
    const s = stateRef.current;
    if (!s.gl || s.disposed) return;
    const initForRace = (s as any).initForRace as ((race: Race) => Promise<void>) | undefined;
    if (initForRace) void initForRace(props.race).catch((err) => console.error(err));
  }, [props.race]);

  return (
    <canvas
      ref={canvasRef}
      style={{ position: 'absolute', inset: '0', width: '100%', height: '100%', display: 'block', pointerEvents: 'none' }}
    />
  );
}

import { useEffect, useRef } from 'react';
import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
import { mat3, mat4, quat, vec3 } from 'gl-matrix';
import type { Race } from '../lib/types';

type ModelType = ReturnType<typeof parseMDX>;
type WorkerSide = 'left' | 'right';

interface WorkerUnitConfig {
