  Orc: { modelPath: '/models/worker-units/Orc/peon.mdx', textures: { 'units/orc/peon/peon.blp': '/models/worker-units/Orc/peon.blp', 'textures/gutz.blp': '/models/worker-units/textures/gutz.blp' } },
  NightElf: { modelPath: '/models/worker-units/NightElf/Archer.mdx', textures: { 'textures/ranger.blp': '/models/worker-units/textures/Ranger.blp', 'textures/star2_32.blp': '/models/worker-units/textures/star2_32.blp', 'textures/gutz.blp': '/models/worker-units/textures/gutz.blp' } },
  Undead: { modelPath: '/models/worker-units/Undead/Acolyte.mdx', textures: { 'textures/acolyte.blp': '/models/worker-units/textures/Acolyte.blp', 'textures/green_star.blp': '/models/worker-units/textures/Green_Star.blp', 'textures/demonrune3.blp': '/models/worker-units/textures/DemonRune3.blp', 'textures/gutz.blp': '/models/worker-units/textures/gutz.blp' } },
};

const modelCache = new Map<string, ModelType>();
const blpCache = new Map<string, ImageData[]>();

function normalizeTexturePath(textureImage: string): string { return textureImage.replaceAll('\\', '/').toLowerCase(); }

function getTexturePath(textureImage: string, race: Race): string | null {
  const normalized = normalizeTexturePath(textureImage);
  if (!normalized) return null;
  return WORKER_UNIT_CONFIG[race].textures[normalized] || null;
}

async function loadModel(path: string): Promise<ModelType> {
  const cached = modelCache.get(path);
  if (cached) return cached;
  const res = await fetch(path);
  if (!res.ok) throw new Error(`Failed to load worker unit model: ${path}`);
  const ab = await res.arrayBuffer();
  const model = parseMDX(ab);
  modelCache.set(path, model);
  return model;
}

async function loadBLPMips(path: string): Promise<ImageData[]> {
  const cached = blpCache.get(path);
  if (cached) return cached;
  const res = await fetch(path);
  if (!res.ok) throw new Error(`Failed to load worker unit texture: ${path}`);
  const ab = await res.arrayBuffer();
  const blp = decodeBLP(ab);
  const mips: ImageData[] = [];
  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
  for (let i = 0; i < maxLevels; i++) {
    const w = blp.width >> i; const h = blp.height >> i;
    if (w <= 0 || h <= 0) break;
    try {
      const img = getBLPImageData(blp, i);
      if (!img || !img.width || !img.height) break;
      mips.push(new ImageData(img.data, img.width, img.height));
      if (img.width === 1 && img.height === 1) break;
    } catch { break; }
  }
  if (mips.length === 0) throw new Error(`No mip levels decoded for worker unit texture: ${path}`);
  blpCache.set(path, mips);
  return mips;
}

function findIdleSequenceIndex(model: ModelType, race: Race): number {
  const sequences = model.Sequences || [];
  if (sequences.length === 0) return 0;
  const sequenceNames = sequences.map((seq) => (seq.Name || '').toLowerCase());
  const preferencesByRace: Record<Race, readonly string[]> = {
    Human: ['stand work', 'stand lumber', 'stand ready', 'stand gold', 'stand - 3', 'stand -3', 'stand 2', 'stand - 2', 'stand'],
    Orc: ['stand ready', 'stand - stretch', 'stand - itch head', 'stand - talk gesture', 'stand 2', 'stand - 2', 'stand'],
    NightElf: ['stand ready', 'stand - 3', 'stand -3', 'stand 2', 'stand - 2', 'stand'],
    Undead: ['stand work', 'stand 2', 'stand - 2', 'stand ready', 'stand'],
  };
  for (const pref of preferencesByRace[race]) {
    const idx = sequenceNames.findIndex((name) => name.includes(pref));
    if (idx >= 0) return idx;
  }
  const fallback = sequenceNames.findIndex((name) => name.includes('stand') && !name.includes('death') && !name.includes('decay'));
  return fallback >= 0 ? fallback : 0;
}

function getSequenceInterval(model: ModelType, index: number): { start: number; length: number } {
  const seq = model.Sequences?.[index];
  const start = seq?.Interval?.[0] ?? 0;
  const end = seq?.Interval?.[1] ?? (start + 1000);
  return { start, length: Math.max(1, end - start) };
}

function getExtentsForSequence(model: ModelType, sequenceIndex: number): { min: readonly [number, number, number] | null; max: readonly [number, number, number] | null } {
  const seq = model.Sequences?.[sequenceIndex];
  const seqMin = seq?.MinimumExtent; const seqMax = seq?.MaximumExtent;
  if (seqMin && seqMax) return { min: [seqMin[0], seqMin[1], seqMin[2]], max: [seqMax[0], seqMax[1], seqMax[2]] };
  const modelMin = model.Info?.MinimumExtent; const modelMax = model.Info?.MaximumExtent;
  if (modelMin && modelMax) return { min: [modelMin[0], modelMin[1], modelMin[2]], max: [modelMax[0], modelMax[1], modelMax[2]] };
  return { min: null, max: null };
}

interface WorkerUnitModelProps { race: Race; side: WorkerSide; }

export default function WorkerUnitModel(props: WorkerUnitModelProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef({
    gl: null as WebGLRenderingContext | WebGL2RenderingContext | null,
    modelRenderer: null as ModelRenderer | null,
    resizeObserver: null as ResizeObserver | null,
    rafId: 0, disposed: false, initVersion: 0,
    sequenceIndex: 0, sequenceStart: 0, sequenceLength: 1000, animStartMs: 0,
    mvMatrix: mat4.create(), pMatrix: mat4.create(), worldCameraMatrix: mat4.create(),
    cameraPos: vec3.create(), cameraTarget: vec3.create(), cameraQuat: quat.create(),
    cameraFov: 0.78, cameraNear: 8, cameraFar: 2400,
  });

  useEffect(() => {
    const s = stateRef.current;
    const canvas = canvasRef.current!;

    const destroyRenderer = () => {
      if (!s.modelRenderer) return;
      try { s.modelRenderer.destroy(); } catch (err) { console.warn('worker unit renderer destroy failed', err); }
      finally { s.modelRenderer = null; }
    };

    const updateProjection = () => {
      const aspect = Math.max(1e-6, canvas.clientWidth / Math.max(1, canvas.clientHeight));
      mat4.perspective(s.pMatrix, s.cameraFov, aspect, s.cameraNear, s.cameraFar);
    };

    const resizeCanvas = () => {
      if (!s.gl) return;
      const dpr = window.devicePixelRatio || 1;
      const w = Math.max(1, Math.round(canvas.clientWidth * dpr));
      const h = Math.max(1, Math.round(canvas.clientHeight * dpr));
      if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; }
      s.gl.viewport(0, 0, w, h);
      updateProjection();
    };

    const configureCamera = (model: ModelType, sequenceIdx: number) => {
      const extents = getExtentsForSequence(model, sequenceIdx);
      const extMin = extents.min; const extMax = extents.max;
      if (extMin && extMax) {
        const cx = (extMin[0] + extMax[0]) * 0.5, cy = (extMin[1] + extMax[1]) * 0.5, cz = (extMin[2] + extMax[2]) * 0.5;
        const dx = extMax[0] - extMin[0], dy = extMax[1] - extMin[1], dz = extMax[2] - extMin[2];
        const rawRadius = Math.hypot(dx, dy, dz) * 0.5;
        const radius = Math.min(190, Math.max(100, rawRadius));
        const height = Math.min(220, Math.max(90, dz));
        vec3.set(s.cameraPos, cx + radius * 0.42, cy - radius * 2.25, cz + height * 0.62);
        vec3.set(s.cameraTarget, cx, cy, cz + height * 0.18);
        s.cameraFov = 0.86; s.cameraNear = Math.max(8, radius * 0.08); s.cameraFar = Math.max(s.cameraNear + 300, radius * 11.5);
      } else {
        vec3.set(s.cameraPos, 48, -420, 180); vec3.set(s.cameraTarget, 0, 0, 100);
        s.cameraFov = 0.78; s.cameraNear = 8; s.cameraFar = 2200;
      }
      mat4.lookAt(s.mvMatrix, s.cameraPos, s.cameraTarget, vec3.fromValues(0, 0, 1));
      if (mat4.invert(s.worldCameraMatrix, s.mvMatrix)) {
        const rot = mat3.create(); mat3.fromMat4(rot, s.worldCameraMatrix);
        quat.fromMat3(s.cameraQuat, rot); quat.normalize(s.cameraQuat, s.cameraQuat);
      } else { quat.identity(s.cameraQuat); }
    };

    const startRenderLoop = () => {
      const speed = 0.8;
      const tick = (now: number) => {
        if (s.disposed) return;
        s.rafId = requestAnimationFrame(tick);
        if (!s.gl || !s.modelRenderer) return;
        resizeCanvas();
        const elapsed = (now - s.animStartMs) * speed;
        const frame = s.sequenceStart + (elapsed % s.sequenceLength);
        s.modelRenderer.setSequence(s.sequenceIndex);
        s.modelRenderer.setFrame(frame);
        s.modelRenderer.update(0);
        s.gl.clearColor(0, 0, 0, 0);
        s.gl.clear(s.gl.COLOR_BUFFER_BIT | s.gl.DEPTH_BUFFER_BIT);
        s.modelRenderer.render(s.mvMatrix, s.pMatrix, { env: false, wireframe: false });
      };
      s.rafId = requestAnimationFrame(tick);
    };

    const initForRace = async (race: Race, side: WorkerSide) => {
      const version = ++s.initVersion;
      const cfg = WORKER_UNIT_CONFIG[race];
      const model = await loadModel(cfg.modelPath);
      if (s.disposed || version !== s.initVersion || !s.gl) return;
      destroyRenderer();
      s.modelRenderer = new ModelRenderer(model);
      s.modelRenderer.initGL(s.gl);
      s.sequenceIndex = findIdleSequenceIndex(model, race);
      const interval = getSequenceInterval(model, s.sequenceIndex);
      s.sequenceStart = interval.start; s.sequenceLength = interval.length;
      configureCamera(model, s.sequenceIndex);
      s.modelRenderer.setCamera(s.cameraPos, s.cameraQuat);
      s.modelRenderer.setLightPosition(s.cameraPos);
      s.modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
      s.modelRenderer.setSequence(s.sequenceIndex);
      s.animStartMs = performance.now();
      const texturePromises = (model.Textures || []).map(async (tex) => {
        const texturePath = getTexturePath(tex.Image, race);
        if (!texturePath) return;
        try {
          const mips = await loadBLPMips(texturePath);
          if (!s.disposed && version === s.initVersion) s.modelRenderer!.setTextureImageData(tex.Image, mips);
        } catch (err) { console.warn(`failed to load worker texture ${texturePath}`, err); }
      });
      await Promise.all(texturePromises);
    };

    (s as any).initForRace = initForRace;

    s.gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false }) as WebGL2RenderingContext | null;
    if (!s.gl) s.gl = canvas.getContext('webgl', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false });
    if (!s.gl) return;

    resizeCanvas();
    s.resizeObserver = new ResizeObserver(() => resizeCanvas());
    s.resizeObserver.observe(canvas);
    startRenderLoop();
    void initForRace(props.race, props.side).catch((err) => console.error(err));

    return () => {
      s.disposed = true; s.initVersion++;
      cancelAnimationFrame(s.rafId);
      s.resizeObserver?.disconnect();
      destroyRenderer();
    };
  }, []);

  useEffect(() => {
    const s = stateRef.current;
    if (!s.gl || s.disposed) return;
    const initForRace = (s as any).initForRace as ((race: Race, side: WorkerSide) => Promise<void>) | undefined;
    if (initForRace) void initForRace(props.race, props.side).catch((err) => console.error(err));
  }, [props.race, props.side]);

  return (
    <canvas
      ref={canvasRef}
      style={{ position: 'absolute', inset: '0', width: '100%', height: '100%', display: 'block', pointerEvents: 'none' }}
    />
  );
}

import { useState, useEffect, useRef } from 'react';
import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
import { mat4, quat, vec3 } from 'gl-matrix';
import { RACE_PREFIXES } from '../state/race';
import type { Race } from '../lib/types';

type ModelType = ReturnType<typeof parseMDX>;

const modelCache = new Map<Race, ModelType>();
const blpCache = new Map<string, ImageData[]>();
const widgetMaskCache = new Map<Race, string>();

function computeVisibleBounds2D(model: ModelType): { minX: number; maxX: number; minY: number; maxY: number } | null {
  let minX = Number.POSITIVE_INFINITY, maxX = Number.NEGATIVE_INFINITY;
  let minY = Number.POSITIVE_INFINITY, maxY = Number.NEGATIVE_INFINITY;
  let hasVisible = false;
  for (const geoset of model.Geosets || []) {
    if (!geoset.Faces || geoset.Faces.length === 0) continue;
    const verts = geoset.Vertices;
    for (let i = 0; i < verts.length; i += 3) {
      const x = verts[i]; const y = verts[i + 1];
      if (x < minX) minX = x; if (x > maxX) maxX = x;
      if (y < minY) minY = y; if (y > maxY) maxY = y;
      hasVisible = true;
    }
  }
  return hasVisible ? { minX, maxX, minY, maxY } : null;
}

function disableBackdropQuads(model: ModelType): void {
  const hiddenNodes = new Set(['plane01', 'sunrise/set']);
  for (const geoset of model.Geosets || []) {
    const nodeIndex = geoset.Groups?.[0]?.[0];
    if (nodeIndex == null) continue;
    const nodeName = model.Nodes?.[nodeIndex]?.Name?.toLowerCase();
    if (!nodeName || !hiddenNodes.has(nodeName)) continue;
    geoset.Faces = new Uint16Array(0);
  }
}

function getModelPath(race: Race): string {
  return `/models/time-indicator/${RACE_PREFIXES[race].tile}UI-TimeIndicator.mdx`;
}

function getClockTexturePath(textureImage: string, race: Race): string | null {
  const norm = textureImage.replaceAll('\\', '/').toLowerCase();
  const tile = RACE_PREFIXES[race].tile;
  const base = `/models/time-indicator/textures/${race}/`;
  if (norm.includes('genericglowfaded')) return `${base}GenericGlowFaded.blp`;
  if (norm.includes('star3')) return `${base}star3.blp`;
  if (norm.includes('genericglow2_32')) return `${base}GenericGlow2_32.blp`;
  if (norm.includes('timeindicatorframe')) return `${base}${tile}UITile-TimeIndicatorFrame.blp`;
  if (norm.includes('timeindicator')) return `${base}HumanUITile-TimeIndicator.blp`;
  return null;
}

function getFrameTexturePath(race: Race): string {
  return `/models/time-indicator/textures/${race}/${RACE_PREFIXES[race].tile}UITile-TimeIndicatorFrame.blp`;
}

function findTransparentSeed(alpha: Uint8ClampedArray, width: number, height: number, startX: number, startY: number): number {
  const inBounds = (x: number, y: number) => x >= 0 && y >= 0 && x < width && y < height;
  const alphaAt = (x: number, y: number) => alpha[(y * width + x) * 4 + 3];
  if (inBounds(startX, startY) && alphaAt(startX, startY) === 0) return startY * width + startX;
  const maxRadius = Math.max(width, height);
  for (let r = 1; r < maxRadius; r++) {
    for (let dy = -r; dy <= r; dy++) {
      const y = startY + dy;
      const x1 = startX - r; const x2 = startX + r;
      if (inBounds(x1, y) && alphaAt(x1, y) === 0) return y * width + x1;
      if (inBounds(x2, y) && alphaAt(x2, y) === 0) return y * width + x2;
    }
    for (let dx = -r + 1; dx <= r - 1; dx++) {
      const x = startX + dx;
      const y1 = startY - r; const y2 = startY + r;
      if (inBounds(x, y1) && alphaAt(x, y1) === 0) return y1 * width + x;
      if (inBounds(x, y2) && alphaAt(x, y2) === 0) return y2 * width + x;
    }
  }
  return -1;
}

async function loadWidgetMaskDataUrl(race: Race): Promise<string> {
  const cached = widgetMaskCache.get(race);
  if (cached) return cached;
  const frame = (await loadBLPMips(getFrameTexturePath(race)))[0];
  if (!frame || frame.width <= 0 || frame.height <= 0) throw new Error(`Invalid frame texture for ${race}`);
  const width = frame.width; const height = frame.height;
  const seedX = Math.round(width * 0.49); const seedY = Math.round(height * 0.34);
  const seed = findTransparentSeed(frame.data, width, height, seedX, seedY);
  if (seed < 0) throw new Error(`Unable to locate clock aperture for ${race}`);
  const aperture = new Uint8Array(width * height);
  const queue = new Int32Array(width * height);
  let head = 0; let tail = 0;
  queue[tail++] = seed; aperture[seed] = 1;
  while (head < tail) {
    const cur = queue[head++]; const x = cur % width; const y = (cur / width) | 0;
    for (const [nx, ny] of [[x-1,y],[x+1,y],[x,y-1],[x,y+1]]) {
      if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
      const next = ny * width + nx;
      if (aperture[next]) continue;
      if (frame.data[next * 4 + 3] !== 0) continue;
      aperture[next] = 1; queue[tail++] = next;
    }
  }
  const pixels = new Uint8ClampedArray(width * height * 4);
  for (let i = 0; i < width * height; i++) {
    const keep = frame.data[i * 4 + 3] > 0 || aperture[i] === 1;
    if (!keep) continue;
    const p = i * 4; pixels[p] = 255; pixels[p+1] = 255; pixels[p+2] = 255; pixels[p+3] = 255;
  }
  const canvas = document.createElement('canvas'); canvas.width = width; canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('Failed to create widget mask canvas');
  ctx.putImageData(new ImageData(pixels, width, height), 0, 0);
  const dataUrl = canvas.toDataURL('image/png');
  widgetMaskCache.set(race, dataUrl);
  return dataUrl;
}

async function loadModelForRace(race: Race): Promise<ModelType> {
  const cached = modelCache.get(race);
  if (cached) return cached;
  const res = await fetch(getModelPath(race));
  if (!res.ok) throw new Error(`Failed to fetch clock model for ${race}`);
  const ab = await res.arrayBuffer();
  const model = parseMDX(ab);
  disableBackdropQuads(model);
  modelCache.set(race, model);
  return model;
}

async function loadBLPMips(path: string): Promise<ImageData[]> {
  const cached = blpCache.get(path);
  if (cached) return cached;
  const res = await fetch(path);
  if (!res.ok) throw new Error(`Failed to fetch texture ${path}`);
  const ab = await res.arrayBuffer();
  const blp = decodeBLP(ab);
  const mips: ImageData[] = [];
  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
  for (let i = 0; i < maxLevels; i++) {
    const w = blp.width >> i; const h = blp.height >> i;
    if (w <= 0 || h <= 0) break;
    try {
      const img = getBLPImageData(blp, i);
      if (!img || !img.width || !img.height) break;
      mips.push(new ImageData(img.data, img.width, img.height));
      if (img.width === 1 && img.height === 1) break;
    } catch { break; }
  }
  if (mips.length === 0) throw new Error(`No mip levels decoded for ${path}`);
  blpCache.set(path, mips);
  return mips;
}

interface TimeIndicatorModelProps { race: Race; }

export default function TimeIndicatorModel(props: TimeIndicatorModelProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [widgetMaskUrl, setWidgetMaskUrl] = useState('');
  const stateRef = useRef({
    gl: null as WebGLRenderingContext | WebGL2RenderingContext | null,
    modelRenderer: null as ModelRenderer | null,
    rafId: 0,
    resizeObserver: null as ResizeObserver | null,
    disposed: false,
    initVersion: 0,
    viewMinX: 0, viewMaxX: 1, viewMinY: 0, viewMaxY: 1,
    mvMatrix: mat4.create(),
    pMatrix: mat4.create(),
  });

  useEffect(() => {
    const s = stateRef.current;
    const canvas = canvasRef.current!;

    const destroyRenderer = () => {
      if (!s.modelRenderer) return;
      try { s.modelRenderer.destroy(); } catch (err) { console.warn('clock renderer destroy failed', err); }
      finally { s.modelRenderer = null; }
    };

    const resizeCanvas = () => {
      if (!s.gl) return;
      const dpr = window.devicePixelRatio || 1;
      const w = Math.max(1, Math.round(canvas.clientWidth * dpr));
      const h = Math.max(1, Math.round(canvas.clientHeight * dpr));
      if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; }
      s.gl.viewport(0, 0, w, h);
    };

    const startRenderLoop = () => {
      const startTs = performance.now();
      const tick = (now: number) => {
        if (s.disposed) return;
        s.rafId = requestAnimationFrame(tick);
        if (!s.gl || !s.modelRenderer) return;
        resizeCanvas();
        const frame = ((now - startTs) * 1.0) % 60000;
        s.modelRenderer.setSequence(0);
        s.modelRenderer.setFrame(frame);
        s.modelRenderer.update(0);
        mat4.identity(s.mvMatrix);
        const baseW = Math.max(1e-6, s.viewMaxX - s.viewMinX);
        const baseH = Math.max(1e-6, s.viewMaxY - s.viewMinY);
        const cx = (s.viewMinX + s.viewMaxX) * 0.5;
        const cy = (s.viewMinY + s.viewMaxY) * 0.5;
        const canvasAspect = Math.max(1e-6, canvas.clientWidth / Math.max(1, canvas.clientHeight));
        const modelAspect = baseW / baseH;
        let viewW = baseW * 1.04; let viewH = baseH * 1.04;
        if (canvasAspect > modelAspect) viewW = viewH * canvasAspect;
        else viewH = viewW / canvasAspect;
        mat4.ortho(s.pMatrix, cx - viewW * 0.5, cx + viewW * 0.5, cy - viewH * 0.5, cy + viewH * 0.5, -10, 10);
        s.gl.clearColor(0, 0, 0, 0);
        s.gl.clear(s.gl.COLOR_BUFFER_BIT | s.gl.DEPTH_BUFFER_BIT);
        s.modelRenderer.render(s.mvMatrix, s.pMatrix, { env: false, wireframe: false });
      };
      s.rafId = requestAnimationFrame(tick);
    };

    const initForRace = async (race: Race) => {
      const version = ++s.initVersion;
      const model = await loadModelForRace(race);
      if (s.disposed || version !== s.initVersion) return;
      destroyRenderer();
      s.modelRenderer = new ModelRenderer(model);
      s.modelRenderer.initGL(s.gl!);
      s.modelRenderer.setCamera(vec3.fromValues(0, 0, 2), quat.fromValues(0, 0, 0, 1));
      s.modelRenderer.setLightPosition(vec3.fromValues(0, 0, 2));
      s.modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
      const bounds = computeVisibleBounds2D(model);
      if (bounds) {
        s.viewMinX = bounds.minX; s.viewMaxX = bounds.maxX;
        s.viewMinY = bounds.minY; s.viewMaxY = bounds.maxY;
      } else {
        const extMin = model.Info?.MinimumExtent; const extMax = model.Info?.MaximumExtent;
        if (extMin && extMax) { s.viewMinX = extMin[0]; s.viewMaxX = extMax[0]; s.viewMinY = extMin[1]; s.viewMaxY = extMax[1]; }
      }
      const texturePromises = (model.Textures || []).map(async (tex) => {
        const path = getClockTexturePath(tex.Image, race);
        if (!path) return;
        const mips = await loadBLPMips(path);
        if (!s.disposed && version === s.initVersion) s.modelRenderer!.setTextureImageData(tex.Image, mips);
      });
      const [maskUrl] = await Promise.all([loadWidgetMaskDataUrl(race), Promise.all(texturePromises)]);
      if (s.disposed || version !== s.initVersion) return;
      setWidgetMaskUrl(maskUrl);
      s.modelRenderer.setSequence(0);
    };

    (s as any).initForRace = initForRace;

    s.gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false }) as WebGL2RenderingContext | null;
    if (!s.gl) s.gl = canvas.getContext('webgl', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false });
    if (!s.gl) return;

    resizeCanvas();
    s.resizeObserver = new ResizeObserver(() => resizeCanvas());
    s.resizeObserver.observe(canvas);
    startRenderLoop();
    void initForRace(props.race);

    return () => {
      s.disposed = true; s.initVersion++;
      cancelAnimationFrame(s.rafId);
      s.resizeObserver?.disconnect();
      destroyRenderer();
    };
  }, []);

  useEffect(() => {
    const s = stateRef.current;
    if (!s.gl || s.disposed) return;
    const initForRace = (s as any).initForRace as ((race: Race) => Promise<void>) | undefined;
    if (initForRace) void initForRace(props.race);
  }, [props.race]);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute', inset: '0', width: '100%', height: '100%', display: 'block', pointerEvents: 'none',
        maskImage: widgetMaskUrl ? `url("${widgetMaskUrl}")` : 'none',
        WebkitMaskImage: widgetMaskUrl ? `url("${widgetMaskUrl}")` : 'none',
        maskRepeat: 'no-repeat', WebkitMaskRepeat: 'no-repeat',
        maskSize: '100% 100%', WebkitMaskSize: '100% 100%',
        maskPosition: 'center', WebkitMaskPosition: 'center',
      } as React.CSSProperties}
    />
  );
}

import { useState, useEffect, useRef } from 'react';
import type { Renderer } from '../renderer/Renderer';
import { useCurrentRace, setCurrentRace, RACE_PREFIXES } from '../state/race';
import { useGoldCurrent, useLumberCurrent } from '../state/resources';
import type { Race } from '../lib/types';
import TimeIndicatorModel from './TimeIndicatorModel';

interface Props {
  renderer: Renderer;
}

const RACES: Race[] = ['Human', 'Orc', 'NightElf', 'Undead'];

export default function TopHud(props: Props) {
  const race = useCurrentRace();

  return (
    <div className="top-hud">
      <div className="top-hud-tiles">
        <div className="top-hud-left">
          <div className="ths ths-1" />
          <div className="ths ths-2" />
        </div>
        <div className="top-hud-right">
          <div className="ths ths-3" />
          <div className="ths ths-4" />
          <div className="ths ths-5" />
        </div>
      </div>
      <div className="time-indicator">
        <TimeIndicatorModel race={race} />
      </div>
      <div className="top-hud-overlay">
        <div className="upper-buttons">
          {RACES.map((r) =>
            <UpperButton key={r} race={r} renderer={props.renderer} />
          )}
        </div>
        <div className="resources">
          <ResourceSlot type="gold" renderer={props.renderer} />
          <ResourceSlot type="lumber" renderer={props.renderer} />
          <ResourceSlot type="supply" renderer={props.renderer} />
          <span className="upkeep-text upkeep-green">No Upkeep</span>
        </div>
      </div>
    </div>
  );
}

function UpperButton(props: { race: Race; renderer: Renderer }) {
  const ref = useRef<HTMLButtonElement>(null);
  const [hovered, setHovered] = useState(false);
  const [pressed, setPressed] = useState(false);
  const currentRace = useCurrentRace();

  useEffect(() => {
    props.renderer.upperButtons.push({
      ref: () => ref.current!,
      race: props.race,
      hovered: () => hovered,
      pressed: () => pressed,
    });
  }, []);

  return (
    <button
      ref={ref}
      className={`upper-btn${currentRace === props.race ? ' active' : ''}`}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setHovered(false); setPressed(false); }}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      onClick={() => setCurrentRace(props.race)}
    >
      {RACE_PREFIXES[props.race].display}
    </button>
  );
}

function ResourceSlot(props: { type: 'gold' | 'lumber' | 'supply'; renderer: Renderer }) {
  const imgRef = useRef<HTMLImageElement>(null);
  const currentRace = useCurrentRace();
  const gold = useGoldCurrent();
  const lumber = useLumberCurrent();

  useEffect(() => {
    props.renderer.resourceIcons.push({
      ref: () => imgRef.current!,
      type: props.type,
    });
  }, []);

  const imgSrc = props.type === 'gold'
    ? 'war3/Feedback/Resources/ResourceGold.png'
    : props.type === 'lumber'
      ? 'war3/Feedback/Resources/ResourceLumber.png'
      : `war3/Feedback/Resources/Resource${currentRace}.png`;

  const value = props.type === 'gold' ? gold
    : props.type === 'lumber' ? lumber
    : '50 / 80';

  return (
    <div className="resource-slot">
      <img ref={imgRef} src={imgSrc} alt={props.type} />
      <span className="res-value">{value}</span>
    </div>
  );
}

