  });

  createEffect(() => {
    const race = props.race;
    if (!gl) return;
    void initForRace(race).catch((err) => console.error(err));
  });

  onCleanup(() => {
    disposed = true;
    initVersion++;
    cancelAnimationFrame(rafId);
    resizeObserver?.disconnect();
    destroyRenderer();
  });

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute',
        inset: '0',
        width: '100%',
        height: '100%',
        display: 'block',
        'pointer-events': 'none',
      }}
    />
  );
}

