      [x - 1, y],
      [x + 1, y],
      [x, y - 1],
      [x, y + 1],
    ];
    for (const [nx, ny] of neighbors) {
      if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
      const next = ny * width + nx;
      if (aperture[next]) continue;
      if (frame.data[next * 4 + 3] !== 0) continue;
      aperture[next] = 1;
      queue[tail++] = next;
    }
  }

  const pixels = new Uint8ClampedArray(width * height * 4);
  for (let i = 0; i < width * height; i++) {
    const frameOpaque = frame.data[i * 4 + 3] > 0;
    const keep = frameOpaque || aperture[i] === 1;
    if (!keep) continue;
    const p = i * 4;
    pixels[p + 0] = 255;
    pixels[p + 1] = 255;
    pixels[p + 2] = 255;
    pixels[p + 3] = 255;
  }

  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('Failed to create widget mask canvas');
  ctx.putImageData(new ImageData(pixels, width, height), 0, 0);
  const dataUrl = canvas.toDataURL('image/png');
  widgetMaskCache.set(race, dataUrl);
  return dataUrl;
}

async function loadModel(race: Race): Promise<ModelType> {
  const cached = modelCache.get(race);
  if (cached) return cached;
  const res = await fetch(getModelPath(race));
  if (!res.ok) throw new Error(`Failed to fetch clock model for ${race}`);
  const ab = await res.arrayBuffer();
  const model = parseMDX(ab);
  disableBackdropQuads(model);
  modelCache.set(race, model);
  return model;
}

async function loadBLPMips(path: string): Promise<ImageData[]> {
  const cached = blpCache.get(path);
  if (cached) return cached;
  const res = await fetch(path);
  if (!res.ok) throw new Error(`Failed to fetch texture ${path}`);
  const ab = await res.arrayBuffer();
  const blp = decodeBLP(ab);
  const mips: ImageData[] = [];
  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
  for (let i = 0; i < maxLevels; i++) {
    const w = blp.width >> i;
    const h = blp.height >> i;
    if (w <= 0 || h <= 0) break;
    try {
      const img = getBLPImageData(blp, i);
      if (!img || !img.width || !img.height) break;
      mips.push(new ImageData(img.data, img.width, img.height));
      if (img.width === 1 && img.height === 1) break;
    } catch {
      // Some files expose invalid trailing mip entries; keep the valid levels we already decoded.
      break;
    }
  }
  if (mips.length === 0) {
    throw new Error(`No mip levels decoded for ${path}`);
  }
  blpCache.set(path, mips);
  return mips;
}

interface TimeIndicatorModelProps {
  race: Race;
}

export default function TimeIndicatorModel(props: TimeIndicatorModelProps) {
  let canvasRef!: HTMLCanvasElement;
  const [status, setStatus] = createSignal('init');
  const [widgetMaskUrl, setWidgetMaskUrl] = createSignal('');
  let gl: WebGLRenderingContext | WebGL2RenderingContext | null = null;
  let modelRenderer: ModelRenderer | null = null;
  let rafId = 0;
  let resizeObserver: ResizeObserver | null = null;
  let disposed = false;
  let initVersion = 0;
  let viewMinX = 0;
  let viewMaxX = 1;
  let viewMinY = 0;
  let viewMaxY = 1;

  const mvMatrix = mat4.create();
  const pMatrix = mat4.create();

  const destroyRenderer = () => {
    if (!modelRenderer) return;
    try {
      modelRenderer.destroy();
    } catch (err) {
      console.warn('clock renderer destroy failed', err);
    } finally {
      modelRenderer = null;
    }
  };

  const resizeCanvas = () => {
    if (!canvasRef || !gl) return;
    const dpr = window.devicePixelRatio || 1;
    const w = Math.max(1, Math.round(canvasRef.clientWidth * dpr));
    const h = Math.max(1, Math.round(canvasRef.clientHeight * dpr));
    if (canvasRef.width !== w || canvasRef.height !== h) {
      canvasRef.width = w;
      canvasRef.height = h;
    }
    gl.viewport(0, 0, w, h);
  };

  const startRenderLoop = () => {
    const startTs = performance.now();
    const tick = (now: number) => {
      if (disposed) return;
      rafId = requestAnimationFrame(tick);
      if (!gl) return;
      if (!modelRenderer) {
        setStatus('waiting renderer');
        return;
      }

      resizeCanvas();
      const frame = ((now - startTs) * 1.0) % 60000;
      modelRenderer.setSequence(0);
      modelRenderer.setFrame(frame);
      modelRenderer.update(0);

      mat4.identity(mvMatrix);
      const baseW = Math.max(1e-6, viewMaxX - viewMinX);
      const baseH = Math.max(1e-6, viewMaxY - viewMinY);
      const cx = (viewMinX + viewMaxX) * 0.5;
      const cy = (viewMinY + viewMaxY) * 0.5;
      const canvasAspect = Math.max(1e-6, canvasRef.clientWidth / Math.max(1, canvasRef.clientHeight));
      const modelAspect = baseW / baseH;
      let viewW = baseW * 1.04;
      let viewH = baseH * 1.04;
      if (canvasAspect > modelAspect) {
        viewW = viewH * canvasAspect;
      } else {
        viewH = viewW / canvasAspect;
      }
      mat4.ortho(pMatrix, cx - viewW * 0.5, cx + viewW * 0.5, cy - viewH * 0.5, cy + viewH * 0.5, -10, 10);
      gl.clearColor(0, 0, 0, 0);
      gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
      modelRenderer.render(mvMatrix, pMatrix, { env: false, wireframe: false });
      setStatus('rendering');
    };
    rafId = requestAnimationFrame(tick);
  };

  const initForRace = async (race: Race) => {
    const version = ++initVersion;
    setStatus(`loading model: ${race}`);
    const model = await loadModel(race);
    if (disposed || version !== initVersion) return;

    destroyRenderer();
    modelRenderer = new ModelRenderer(model);
    modelRenderer.initGL(gl!);
    modelRenderer.setCamera(vec3.fromValues(0, 0, 2), quat.fromValues(0, 0, 0, 1));
    modelRenderer.setLightPosition(vec3.fromValues(0, 0, 2));
    modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
    setStatus(`model loaded: ${race}`);

    const bounds = computeVisibleBounds2D(model);
    if (bounds) {
      viewMinX = bounds.minX;
      viewMaxX = bounds.maxX;
      viewMinY = bounds.minY;
      viewMaxY = bounds.maxY;
    } else {
      const extMin = model.Info?.MinimumExtent;
      const extMax = model.Info?.MaximumExtent;
      if (extMin && extMax) {
        viewMinX = extMin[0];
        viewMaxX = extMax[0];
        viewMinY = extMin[1];
        viewMaxY = extMax[1];
      }
    }

    const texturePromises = (model.Textures || []).map(async (tex) => {
      const path = getClockTexturePath(tex.Image, race);
      if (!path) return;
      const mips = await loadBLPMips(path);
      if (!disposed && version === initVersion) {
        modelRenderer!.setTextureImageData(tex.Image, mips);
      }
    });
    const [maskUrl] = await Promise.all([
      loadWidgetMaskDataUrl(race),
      Promise.all(texturePromises),
    ]);
    if (disposed || version !== initVersion) return;
    setWidgetMaskUrl(maskUrl);
    modelRenderer.setSequence(0);
    setStatus(`textures bound: ${race}`);
  };

  onMount(() => {
    gl = canvasRef.getContext('webgl2', {
      alpha: true,
      premultipliedAlpha: false,
      antialias: true,
      depth: true,
      stencil: false,
    }) as WebGL2RenderingContext | null;
    if (!gl) {
      gl = canvasRef.getContext('webgl', {
        alpha: true,
        premultipliedAlpha: false,
        antialias: true,
        depth: true,
        stencil: false,
      });
    }
    if (!gl) {
      setStatus('no webgl context');
      return;
    }

    setStatus('gl context ok');
    resizeCanvas();
    resizeObserver = new ResizeObserver(() => resizeCanvas());
    resizeObserver.observe(canvasRef);
    startRenderLoop();
    void initForRace(props.race);
  });

  createEffect(() => {
    const race = props.race;
    if (!gl) return;
    void initForRace(race);
  });

  onCleanup(() => {
    disposed = true;
    initVersion++;
    cancelAnimationFrame(rafId);
    resizeObserver?.disconnect();
    destroyRenderer();
  });

  return (
    <>
      <canvas
        ref={canvasRef}
        style={{
          position: 'absolute',
          inset: '0',
          width: '100%',
          height: '100%',
          display: 'block',
          'pointer-events': 'none',
          'mask-image': widgetMaskUrl() ? `url("${widgetMaskUrl()}")` : 'none',
          '-webkit-mask-image': widgetMaskUrl() ? `url("${widgetMaskUrl()}")` : 'none',
          'mask-repeat': 'no-repeat',
          '-webkit-mask-repeat': 'no-repeat',
          'mask-size': '100% 100%',
          '-webkit-mask-size': '100% 100%',
          'mask-position': 'center',
          '-webkit-mask-position': 'center',
        }}
      />
    </>
  );
}

